import{_ as l,o as e,c as i,ag as o}from"./chunks/framework.oqSrIbQK.js";const d=JSON.parse('{"title":"我现在对 AI / Agent 开发的一个更合适比喻","description":"","frontmatter":{"title":"我现在对 AI / Agent 开发的一个更合适比喻","date":"2026-04-20T00:00:00.000Z","tags":["AI","Agent","Prompt","Workflow","Harness"],"categories":["AI开发","方法思考"]},"headers":[],"relativePath":"posts/AI-协作与边界/我现在对 AI / Agent 开发的一个更合适比喻.md","filePath":"posts/AI-协作与边界/我现在对 AI / Agent 开发的一个更合适比喻.md","lastUpdated":1777011025000}'),t={name:"posts/AI-协作与边界/我现在对 AI / Agent 开发的一个更合适比喻.md"};function r(p,a,n,h,s,u){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="我现在对-ai-agent-开发的一个更合适比喻" tabindex="-1">我现在对 AI / Agent 开发的一个更合适比喻 <a class="header-anchor" href="#我现在对-ai-agent-开发的一个更合适比喻" aria-label="Permalink to &quot;我现在对 AI / Agent 开发的一个更合适比喻&quot;">​</a></h1><p>最近一直在想，怎么用一个更贴切的比喻来理解 AI / Agent 开发。</p><p>一开始我自己的感觉是：<br> AI 很强，什么都能做，但没有方向。我们要把复杂事情拆成一步步，在每一步里不断告诉它该怎么做、不该怎么做，最后让它从起点走到终点。</p><p>这个理解大方向没错，但总觉得还差一点。<br> 后来想明白了，更合适的比喻其实不是“小球进管道”，而是：</p><blockquote><p><strong>AI 像一个能力很强、反应很快，但缺少稳定业务判断的新员工。</strong></p></blockquote><p>这个比喻比“小球和管子”更贴近真实开发场景。</p><hr><h2 id="为什么-小球和管子-的比喻不够贴切" tabindex="-1">为什么“小球和管子”的比喻不够贴切 <a class="header-anchor" href="#为什么-小球和管子-的比喻不够贴切" aria-label="Permalink to &quot;为什么“小球和管子”的比喻不够贴切&quot;">​</a></h2><p>“小球和管子”的比喻强调的是：</p><ul><li>给它轨道</li><li>给它约束</li><li>让它从起点走到终点</li></ul><p>这个方向本身没问题，但它更像一个物理系统。<br> 而 AI / Agent 真正麻烦的地方，不只是“它会乱跑”，而是：</p><ul><li>它会<strong>自作聪明</strong></li><li>它会<strong>脑补你没说清的部分</strong></li><li>它会输出一堆<strong>看起来很合理，但其实不对</strong>的内容</li><li>它不会天然知道哪一步能自己拍板，哪一步必须停下来问人</li></ul><p>所以，AI 更像是一个“会做事，但不够稳”的参与者，而不是一个被动小球。</p><hr><h2 id="更合适的比喻-ai-像一个很强但不够稳的新员工" tabindex="-1">更合适的比喻：AI 像一个很强但不够稳的新员工 <a class="header-anchor" href="#更合适的比喻-ai-像一个很强但不够稳的新员工" aria-label="Permalink to &quot;更合适的比喻：AI 像一个很强但不够稳的新员工&quot;">​</a></h2><p>这个新员工有什么特点？</p><h3 id="_1-能力强-反应快" tabindex="-1">1. 能力强，反应快 <a class="header-anchor" href="#_1-能力强-反应快" aria-label="Permalink to &quot;1. 能力强，反应快&quot;">​</a></h3><p>你给它一个任务，它很快就能给你一版东西。</p><p>比如：</p><ul><li>写个摘要</li><li>拆个任务</li><li>列个验收标准</li><li>总结风险点</li></ul><p>它大概率都能马上产出。</p><h3 id="_2-但不天然懂真实业务边界" tabindex="-1">2. 但不天然懂真实业务边界 <a class="header-anchor" href="#_2-但不天然懂真实业务边界" aria-label="Permalink to &quot;2. 但不天然懂真实业务边界&quot;">​</a></h3><p>它不知道：</p><ul><li>哪些东西你其实还没想清楚</li><li>哪些地方不能自己拍板</li><li>哪些隐含规则是团队默认的</li><li>哪些边界条件没写出来但必须考虑</li></ul><h3 id="_3-它容易-像对了-不一定-真对了" tabindex="-1">3. 它容易“像对了”，不一定“真对了” <a class="header-anchor" href="#_3-它容易-像对了-不一定-真对了" aria-label="Permalink to &quot;3. 它容易“像对了”，不一定“真对了”&quot;">​</a></h3><p>这点特别关键。</p><p>AI 最大的问题往往不是完全胡说，而是：</p><blockquote><p><strong>输出看起来很顺、很完整、很像那么回事，但其实关键地方偏了。</strong></p></blockquote><p>这比传统报错更难处理。</p><hr><h2 id="如果把-ai-看成一个新员工-那-ai-agent-开发本质上在做什么" tabindex="-1">如果把 AI 看成一个新员工，那 AI / Agent 开发本质上在做什么？ <a class="header-anchor" href="#如果把-ai-看成一个新员工-那-ai-agent-开发本质上在做什么" aria-label="Permalink to &quot;如果把 AI 看成一个新员工，那 AI / Agent 开发本质上在做什么？&quot;">​</a></h2><p>如果真是带一个新员工做事，那我们要做的事情就一下子变得清楚了。</p><hr><h2 id="一、先把大任务拆成小任务" tabindex="-1">一、先把大任务拆成小任务 <a class="header-anchor" href="#一、先把大任务拆成小任务" aria-label="Permalink to &quot;一、先把大任务拆成小任务&quot;">​</a></h2><p>你不能上来就说：</p><blockquote><p>你把这个复杂系统做完。</p></blockquote><p>这太空了。</p><p>你更可能会这样安排：</p><ol><li>先把需求总结清楚</li><li>再划定这次范围</li><li>再拆子任务</li><li>再列验收标准</li><li>再把不确定的地方单独列出来</li><li>最后再进入开发或评审</li></ol><p>这一步，对应的就是：</p><blockquote><p><strong>Workflow / Orchestration</strong></p></blockquote><p>也就是：<br> 不是让 AI 直接完成一切，而是把复杂任务拆成多个阶段。</p><hr><h2 id="二、把工作规范说清楚" tabindex="-1">二、把工作规范说清楚 <a class="header-anchor" href="#二、把工作规范说清楚" aria-label="Permalink to &quot;二、把工作规范说清楚&quot;">​</a></h2><p>带新员工干活，不能只说“做这个”。</p><p>你还要把要求讲清楚：</p><ul><li>输出要按什么结构来</li><li>不确定的地方不能自己猜</li><li>哪些点必须重点关注</li><li>哪些边界不能越过</li><li>哪些结果必须能直接给研发使用</li></ul><p>这一步，对应的就是：</p><blockquote><p><strong>Harness</strong></p></blockquote><p>也就是：<br> 给 AI 加规则、格式、边界和约束，不让它自由发挥到失控。</p><hr><h2 id="三、关键节点必须-review" tabindex="-1">三、关键节点必须 review <a class="header-anchor" href="#三、关键节点必须-review" aria-label="Permalink to &quot;三、关键节点必须 review&quot;">​</a></h2><p>你不能指望新员工一口气做完所有内容再交付。<br> 中间总有几个关键点要停一下看一眼。</p><p>比如：</p><ul><li>你理解的目标是不是对的</li><li>本次范围是不是收住了</li><li>子任务有没有漏关键流程</li><li>验收标准是不是空话</li><li>哪些地方其实还要继续确认</li></ul><p>这一步，对应的就是：</p><blockquote><p><strong>Human-in-the-loop</strong></p></blockquote><p>也就是：<br> 人在关键位置不是可选项，而是工作流本身的一部分。</p><hr><h2 id="四、出错以后不能只说-这次不行" tabindex="-1">四、出错以后不能只说“这次不行” <a class="header-anchor" href="#四、出错以后不能只说-这次不行" aria-label="Permalink to &quot;四、出错以后不能只说“这次不行”&quot;">​</a></h2><p>带新员工最怕的，不是出错，而是出错以后只说一句：</p><blockquote><p>这版不行，你再来一次。</p></blockquote><p>这样没有积累。</p><p>更好的方式是复盘：</p><ul><li>这次到底哪里错了</li><li>是理解偏了，还是规则没给够</li><li>是输出结构没约束住，还是流程里少了检查点</li><li>是不是这类问题以后可以提前拦住</li></ul><p>这一步，对应的就是：</p><blockquote><p><strong>Eval + 失败归档 + 优化闭环</strong></p></blockquote><p>也就是：<br> 不是只看结果有没有出来，而是要看结果质量，并把失败变成后续优化输入。</p><hr><h2 id="这个比喻下-几个核心概念分别是什么" tabindex="-1">这个比喻下，几个核心概念分别是什么 <a class="header-anchor" href="#这个比喻下-几个核心概念分别是什么" aria-label="Permalink to &quot;这个比喻下，几个核心概念分别是什么&quot;">​</a></h2><p>如果继续沿用“新员工”这个比喻，那前面那些抽象概念就可以这样理解。</p><h3 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h3><p>像你在给新员工下达具体任务时说的话。<br> 你交代任务的方式，会直接影响它做出来的结果。</p><h3 id="harness" tabindex="-1">Harness <a class="header-anchor" href="#harness" aria-label="Permalink to &quot;Harness&quot;">​</a></h3><p>像团队里的工作规范、模板、注意事项、检查规则。<br> 它不是结果本身，但它会决定结果会不会跑偏。</p><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><p>像项目推进流程。<br> 先做什么，后做什么，哪一步停下来 review，都属于这里。</p><h3 id="human-in-the-loop" tabindex="-1">Human-in-the-loop <a class="header-anchor" href="#human-in-the-loop" aria-label="Permalink to &quot;Human-in-the-loop&quot;">​</a></h3><p>像关键节点的负责人 review。<br> 有些地方新人可以自己做，有些地方必须让你拍板。</p><h3 id="eval" tabindex="-1">Eval <a class="header-anchor" href="#eval" aria-label="Permalink to &quot;Eval&quot;">​</a></h3><p>像你对交付结果的判断标准。<br> 不是“看起来不错”就算过，而是要判断是不是能真正拿去用。</p><hr><h2 id="还有一个更偏工程化的比喻" tabindex="-1">还有一个更偏工程化的比喻 <a class="header-anchor" href="#还有一个更偏工程化的比喻" aria-label="Permalink to &quot;还有一个更偏工程化的比喻&quot;">​</a></h2><p>如果不想用“新员工”这种更偏人的比喻，也可以换一个更偏技术系统的版本：</p><blockquote><p><strong>AI 像一台马力很大的发动机，但没有方向盘、刹车和仪表盘。</strong></p></blockquote><p>它有能力，很能跑。<br> 但如果你不补上这些东西，它就很危险。</p><h3 id="方向盘" tabindex="-1">方向盘 <a class="header-anchor" href="#方向盘" aria-label="Permalink to &quot;方向盘&quot;">​</a></h3><p>对应的是：</p><ul><li>Workflow</li><li>Orchestration</li></ul><p>决定它往哪走。</p><h3 id="刹车" tabindex="-1">刹车 <a class="header-anchor" href="#刹车" aria-label="Permalink to &quot;刹车&quot;">​</a></h3><p>对应的是：</p><ul><li>人工确认点</li><li>BLOCK</li><li>RETRY_SUGGESTED</li><li>回滚机制</li></ul><p>决定它什么时候必须停下。</p><h3 id="仪表盘" tabindex="-1">仪表盘 <a class="header-anchor" href="#仪表盘" aria-label="Permalink to &quot;仪表盘&quot;">​</a></h3><p>对应的是：</p><ul><li>Eval</li><li>自动校验</li><li>失败案例归档</li></ul><p>决定你能不能看见它到底跑得对不对。</p><h3 id="限速器和护栏" tabindex="-1">限速器和护栏 <a class="header-anchor" href="#限速器和护栏" aria-label="Permalink to &quot;限速器和护栏&quot;">​</a></h3><p>对应的是：</p><ul><li>Harness</li><li>规则</li><li>输出结构</li><li>权限约束</li></ul><p>决定它不能随便越界。</p><p>这个比喻更适合偏技术表达，但我自己还是更喜欢“新员工”的版本，因为它更容易把“自作聪明、像对了但不真对”这种感觉说清楚。</p><hr><h2 id="我现在更认可的一句话" tabindex="-1">我现在更认可的一句话 <a class="header-anchor" href="#我现在更认可的一句话" aria-label="Permalink to &quot;我现在更认可的一句话&quot;">​</a></h2><p>如果让我把现在对 AI / Agent 开发的理解压成一句话，我会更愿意这样说：</p><blockquote><p><strong>AI / Agent 开发，不是让 AI 自己把事情做完，而是像带一个能力很强但不够稳的新员工：把任务拆清楚，把规则讲清楚，把关键检查点放清楚，出错后再复盘为什么错、下次怎么改。</strong></p></blockquote><p>这句话里其实已经包含了：</p><ul><li>Prompt</li><li>Harness</li><li>Workflow</li><li>Human-in-the-loop</li><li>Eval</li><li>优化闭环</li></ul><p>也更接近我现在真正想学会的东西。</p><hr><h2 id="结尾" tabindex="-1">结尾 <a class="header-anchor" href="#结尾" aria-label="Permalink to &quot;结尾&quot;">​</a></h2><p>所以回头看，之前那个“小球进管道”的理解不能说错，但还是偏机械了一点。</p><p>更准确的理解应该是：</p><blockquote><p><strong>AI 不是一个等你控制的小球，而是一个能力很强、会主动输出、也会主动犯错的执行者。</strong></p></blockquote><p>而我们做 AI / Agent 开发，本质上就是：</p><ul><li>给它任务分工</li><li>给它规则边界</li><li>给它检查点</li><li>给它失败后的处理方式</li><li>让它从“会干活”慢慢变成“能稳定干对活”</li></ul><p>这才是我目前觉得更贴切、也更适合长期拿来指导自己学习和做项目的比喻。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre></div>',119)])])}const b=l(t,[["render",r]]);export{d as __pageData,b as default};
